<script>
import lexsemunito_trial    from '../trials/lexsemunito_items.tsv';
import lexsemunito_practice from '../trials/lexsemunito_practice.tsv';
// ─────────────────────────────────────────────────────────────────────────
// CODICE DI COMPLETAMENTO PROLIFIC
// Sostituire il valore con l'URL reale fornito da Prolific prima del lancio.
// Formato: 'https://app.prolific.co/submissions/complete?cc=XXXXXXXX'
// ─────────────────────────────────────────────────────────────────────────
const PROLIFIC_COMPLETION_URL = 'https://app.prolific.co/submissions/complete?cc=DA_CONFIGURARE';
const PROLIFIC_COMPLETION_CODE = PROLIFIC_COMPLETION_URL.split('cc=')[1] || 'DA_CONFIGURARE';

import _ from 'lodash';

export default {
  name: 'App',

  data() {

    // ------------------------------------------------------------------
    // processTrials(): trasforma le righe TSV nel formato usato dal template.
    // Per ogni riga:
    //   - raccoglie le pagine non vuote (page1...page9)
    //   - costruisce un array di domande, ciascuna con le opzioni mescolate
    // ------------------------------------------------------------------
    const processTrials = (trials) => trials.map(trial => {

      // Raccolta pagine: itera da page1 a page9, tiene solo quelle non vuote.
      const pages = [];
      for (let i = 1; i <= 9; i++) {
        const pageText = trial[`page${i}`];
        if (pageText && String(pageText).trim() !== '') {
          pages.push(String(pageText).trim().replace(/\\n/g, '\n'));
        }
      }

      // Raccolta domande: itera da question1 a question6.
      // Per ogni domanda valida, mescola risposta corretta + 3 distrattori.
      const questions = [];
      for (let i = 1; i <= 6; i++) {
        const questionText = trial[`question${i}`];
        if (questionText && String(questionText).trim() !== '') {
          const correct     = String(trial[`response${i}_true`]        || '').replace(/ ?["]+/g, '').trim();
          const distractor1 = String(trial[`response${i}_distractor1`] || '').replace(/ ?["]+/g, '').trim();
          const distractor2 = String(trial[`response${i}_distractor2`] || '').replace(/ ?["]+/g, '').trim();
          const distractor3 = String(trial[`response${i}_distractor3`] || '').replace(/ ?["]+/g, '').trim();

          // Filtra le opzioni vuote (utile per la pratica che potrebbe averne meno)
          const allOptions = [correct, distractor1, distractor2, distractor3]
            .filter(opt => opt !== '');

          questions.push({
            question:         String(questionText).trim(),
            response_options: _.shuffle(allOptions), // mescola per nascondere la posizione della risposta corretta
            correct,                                  // conserva la risposta corretta per l'analisi
          });
        }
      }

      return { ...trial, pages, questions };
    });

    // Processa i trial sperimentali e li mescola casualmente.
    // I trial di pratica vengono anteposti senza mescolamento.
    const shuffledItems  = _.shuffle(processTrials(lexsemunito_trial));
    const practiceItems  = processTrials(lexsemunito_practice);
    const trials         = _.concat(practiceItems, shuffledItems);

    return {
      trials,

      // Stato del mouse tracking
      darkModeDetected: false,  // true se rilevata estensione dark mode (Dark Reader ecc.)
      mobileBlocked:  false,   // true se rilevato smartphone → blocca l'accesso
      tabletWarning:  false,   // true se rilevato tablet → avviso ma non blocco
      pageCheckAnswer: null,    // risposta selezionata al comprehension check della pagina corrente
      ccOptionsCache: {},       // cache opzioni check: { 'trialIndex_pageNr': [opt1, opt2] }
      ccBoxVisible:   true,     // true = box check visibile; false = collassato
      familiarityAnswer: null,       // valore selezionato (0/25/50/75/100)
      visitedWords: {},              // { index: true } — oggetto reattivo (Vue 2 non traccia Set)
      rafId:         null,           // ID requestAnimationFrame — per cancellarla in beforeDestroy
      lastSampleTime: 0,             // DOMHighResTimeStamp dell'ultimo campione salvato
      pageStartTime:  0,             // DOMHighResTimeStamp del click ▶ — per TrialTime relativo
      familiarityOptions: [
        { value:   0, label: 'Non l\'ho mai letto — completamente nuovo per me' },
        { value:  25, label: 'L\'ho sentito nominare / ho letto qualche parte' },
        { value:  50, label: 'Lo conosco abbastanza bene, ma non ricordo tutto' },
        { value:  75, label: 'Lo ricordo bene — l\'ho letto in passato' },
        { value: 100, label: 'Lo conosco molto bene — l\'ho letto di recente o più volte' },
      ],
      isCursorMoving: false,   // sblocca i pulsanti dopo il primo movimento del mouse
      // Flag per mostrare/nascondere l'indicatore di sblocco del pulsante
      // durante la lettura ("Leggi con il mouse per sbloccare..."). Impostare
      // a true per ripristinarne la visibilità.
      showReadingHintIndicator: false,
      currentIndex:   null,    // indice dello <span> sotto il cursore (-1 = area testo ma no span)
      mousePosition:  { x: 0, y: 0 },

      // Stato della navigazione interna al trial
      showFirstDiv:   true,    // true = fase lettura, false = fase domande
      currentPage:    0,       // indice della pagina corrente (0-based)
      readingStarted: false,   // false = mostra pulsante ▶ top-left (punto di fissazione)

      // ── Stato navigazione questionario ──
      questionnaireStep: 1,    // step corrente (1-9)
      currentTrialReadingMs: 0,  // accumula ms di lettura per il trial corrente
      currentTrialStartTime: 0,  // performance.now() quando inizia lo Screen del trial
      experimentStartTime:   0,  // performance.now() a mounted() — per tempo totale
      submitState:   'idle',    // 'idle' | 'sending' | 'success' | 'error'
      contactEmail:    'giorgio.perna905@edu.unito.it',
      completionUrl:   PROLIFIC_COMPLETION_URL,
      completionCode:  PROLIFIC_COMPLETION_CODE,
      codeCopied:      false,  // feedback visivo copia codice
      questionsStartTime:    0,  // performance.now() quando inizia Screen 2
      trialTimeSummary:      [], // [{label, readingMs, questionsMs}] uno per trial
      questionnaireStartTime: 0, // performance.now() quando entra nel questionario
