    };
  },

  computed: {
    // ── Validazione step corrente ──────────────────────────────────────
    currentStepComplete() {
      const m   = this.$magpie.measurements;
      const has = (v) => v !== undefined && v !== null && String(v).trim() !== '';
      const s   = this.questionnaireStep;

      if (s === 1) {
        return has(m.gender) && has(m.age) && Number(m.age) >= 18 &&
               has(m.socio_economic_status) && has(m.years_education) &&
               has(m.level_education) && has(m.eyewear);
      }
      if (s === 2) {
        // confirm_answer obbligatorio; dialetto italiano obbligatorio (select)
        // native_language_2 e native_language_3 sono opzionali (valore '' = nessuna)
        return has(m.confirm_answer) && has(m.native_language_1_dialect);
      }
      if (s === 3) {
        return this.readingCategories.every(cat =>
          has(m[`native_language_1_${cat.key}_reading_time`])
        );
      }
      // Step 4: abitudini lettura lingua nativa 2
      if (s === 4) {
        return has(m.tiredness) && has(m.alcohol_yesterday) && has(m.alcohol_today);
      }
      return true;
    },
  },

  mounted() {
    // ── Rilevamento Dark Reader e estensioni dark mode ─────────────────
    // Doppio metodo con auto-dismiss:
    //
    // Metodo 1 (DOM): osserva l'attributo data-darkreader-mode su <html>.
    //   Presente in tutte le modalità di Dark Reader (static/dynamic/filter).
    //
    // Metodo 2 (CSS probe): un elemento di test bianco nascosto viene
    //   inserito nel DOM; se il suo colore computato non è bianco,
    //   significa che CSS della pagina è stato manomesso.
    //   Verificato ogni 2 secondi via setInterval.
    //
    // Auto-dismiss: quando l'estensione viene disattivata rimuove i propri
    //   attributi dinamicamente. Il MutationObserver chiama updateDarkMode()
    //   che rimette darkModeDetected = false e l'overlay scompare.

    const probe = document.createElement('div');
    probe.setAttribute('data-experiment-probe', 'true');
    probe.style.cssText = [
      'position:fixed',
      'top:-9999px',
      'left:-9999px',
      'width:2px',
      'height:2px',
      'background-color:#ffffff !important',
      'pointer-events:none',
      'z-index:-1',
    ].join(';');
    document.body.appendChild(probe);

    const isDarkModeActive = () => {
      if (document.documentElement.hasAttribute('data-darkreader-mode')) return true;
      const bg = window.getComputedStyle(probe).backgroundColor;
      if (bg && bg !== 'rgb(255, 255, 255)' && bg !== 'rgba(0, 0, 0, 0)' && bg !== '') return true;
      return false;
    };

    // Aggiorna lo stato Vue: viene chiamato sia su attivazione che su
    // disattivazione, quindi imposta sempre il valore corretto (true/false).
    const updateDarkMode = () => {
      this.darkModeDetected = isDarkModeActive();
    };

    // Controllo immediato
    updateDarkMode();

    // MutationObserver: rileva aggiunta/rimozione attributi su <html>
    const darkObserver = new MutationObserver(updateDarkMode);
    darkObserver.observe(document.documentElement, {
      attributes: true,
      attributeFilter: ['data-darkreader-mode', 'data-darkreader-scheme', 'style', 'class'],
    });

    // Polling CSS ogni 2 secondi: cattura manipolazioni che non passano
    // per attributi su <html>
    setInterval(updateDarkMode, 2000);

    // ── Rilevamento dispositivo mobile ───────────────────────────────
    // Blocca se:
    //   1. Lo UA dichiara esplicitamente un dispositivo mobile, OPPURE
    //   2. Il lato corto dello schermo in pixel CSS fisici è < 1024px
    //
    // Usiamo screen.width / DPR invece di window.innerWidth perché in
    // modalità "desktop" i browser mobile impostano innerWidth a valori
    // grandi (~1280px) per simulare un desktop, ma screen.width e DPR
    // rimangono quelli reali dell'hardware:
    //   Galaxy S24: screen.width=2340, DPR=3 → lato corto=360px → blocca
    //   iPad 10":   screen.width=2360, DPR=2 → lato corto=820px → blocca
    //   Laptop 13": screen.width=1920, DPR=1 → lato corto=1080px → ok
    //
    // Nota: il DevTools mobile emulator NON viene bloccato perché usa
    // screen.width e DPR del monitor fisico del computer, non del
    // dispositivo simulato — è un limite noto dell'emulazione browser.
    const ua  = navigator.userAgent;
    const dpr = window.devicePixelRatio || 1;
    const shortSideCss = Math.min(window.screen.width, window.screen.height) / dpr;
    const uaIsMobile   = /iPhone|iPad|Android|BlackBerry|Windows Phone|Mobile/i.test(ua);
    const screenTooSmall = shortSideCss < 1024;

    if (uaIsMobile || screenTooSmall) {
      this.mobileBlocked = true;
    }

    this.experimentStartTime = performance.now(); // tempo totale esperimento


    // Listener tastiera: spazio toglie/mostra il box check
    // Solo se il focus non è su un input (per non interferire con le radio)
    this._ccKeyHandler = (e) => {
      if (e.code !== 'Space') return;
      if (!this.showFirstDiv || !this.readingStarted) return;
      // Non intercettare se il focus è su un elemento che usa spazio
      // per la sua funzione nativa (radio, checkbox, select, button, textarea)
      const tag  = e.target.tagName;
      const type = (e.target.type || '').toLowerCase();
      const isNativeSpaceUser =
        tag === 'TEXTAREA' ||
        tag === 'SELECT'   ||
        (tag === 'INPUT' && (type === 'radio' || type === 'checkbox' || type === 'button')) ||
        (tag === 'BUTTON' && !e.target.classList.contains('eye-btn'));
      if (isNativeSpaceUser) return;
      e.preventDefault();
      this.toggleCcBox();
      // Rimuove il focus da qualsiasi elemento per evitare desync
      if (document.activeElement) document.activeElement.blur();
    };
    document.addEventListener('keydown', this._ccKeyHandler);
  },

  beforeDestroy() {
    this.stopRaf();
    if (this._ccKeyHandler)
      document.removeEventListener('keydown', this._ccKeyHandler);
  },

  methods: {
    // ------------------------------------------------------------------
    // consentAndProceed() — chiamato al click sul pulsante del consenso.
    // Genera un UUID anonimo come SubjectId (magpie lo richiede nella
    // submission) e avanza alla schermata successiva.
    // ------------------------------------------------------------------
    consentAndProceed() {
      const uuid = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
        const r = Math.random() * 16 | 0;
        return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
      });
      $magpie.addExpData({ SubjectId: uuid });
      $magpie.nextScreen();
    },

    // ID custom locale: tre cifre esatte (es. 002, 042, 123)
    // Metodo mantenuto commentato per riferimento futuro; non più usato
    // ora che il campo ID è stato rimosso.
    /*
    isCustomId() {
      const id = this.$magpie.expData && this.$magpie.expData.SubjectId;
      return /^\d{3}$/.test(String(id || '').trim());
    },
    */

    // ------------------------------------------------------------------
    // autoSubmit() — chiamato quando lo Screen di invio viene montato
    // ------------------------------------------------------------------
    async autoSubmit() {
      this.submitState = 'sending';
      try {
        await $magpie.submit();
        this.submitState = 'success';
        // Redirect automatico a Prolific rimosso.
        // Codice precedente conservato per riferimento:
        // if (!this.isCustomId()) {
        //   setTimeout(() => { window.location.href = this.completionUrl; }, 3000);
        // }
      } catch (e) {
        console.error('Submit error:', e);
        this.submitState = 'error';
      }
    },

    // ------------------------------------------------------------------
    // downloadData() — scarica i dati come CSV in caso di errore invio
    // ------------------------------------------------------------------
    copyCode() {
      const code = this.completionCode;
      // Tenta prima con Clipboard API (richiede HTTPS o localhost)
      if (navigator.clipboard && navigator.clipboard.writeText) {
        navigator.clipboard.writeText(code)
          .then(() => {
            this.codeCopied = true;
            setTimeout(() => { this.codeCopied = false; }, 2000);
          })
          .catch(() => this._fallbackCopy(code));
      } else {
        this._fallbackCopy(code);
      }
    },

    _fallbackCopy(text) {
      // Fallback: crea un textarea temporaneo e usa execCommand
      const el = document.createElement('textarea');
      el.value = text;
      el.style.position = 'fixed';
      el.style.opacity  = '0';
      document.body.appendChild(el);
      el.focus();
      el.select();
      const ok = document.execCommand('copy');
      document.body.removeChild(el);
      if (ok) {
        this.codeCopied = true;
        setTimeout(() => { this.codeCopied = false; }, 2000);
      }
    },

    downloadData() {
      try {
        const rows = $magpie.getAllData();
        if (!rows || !rows.length) return;
        const keys = Object.keys(rows[0]);
        const csv  = [keys.join(','),
          ...rows.map(r => keys.map(k => JSON.stringify(r[k] !== null && r[k] !== undefined ? r[k] : '')).join(','))
        ].join('\n');
        const blob = new Blob([csv], { type: 'text/csv' });
        const url  = URL.createObjectURL(blob);
        const a    = document.createElement('a');
        a.href     = url;
        a.download = 'lexsemunito_dati.csv';
        a.click();
        URL.revokeObjectURL(url);
      } catch (e) {
        console.error('Download error:', e);
      }
    },

    // ------------------------------------------------------------------
    // toggleCcBox() — mostra/nasconde il box del comprehension check
    // Attivato dal pulsante toggle o dalla barra spaziatrice
    // ------------------------------------------------------------------
    toggleCcBox() {
      this.ccBoxVisible = !this.ccBoxVisible;
    },

    // ------------------------------------------------------------------
    // startRaf() / stopRaf() — avvia e ferma il loop di campionamento
    // Il rAF gira SOLO durante la lettura attiva (dopo click ▶).
    // ------------------------------------------------------------------
    startRaf() {
      if (this.rafId) return;  // già in esecuzione
      const rafLoop = (timestamp) => {
        if (timestamp - this.lastSampleTime >= 50) {
          this.lastSampleTime = timestamp;
          this.saveData(timestamp);
        }
        this.rafId = requestAnimationFrame(rafLoop);
      };
      this.rafId = requestAnimationFrame(rafLoop);
    },

    stopRaf() {
      if (this.rafId) {
        cancelAnimationFrame(this.rafId);
        this.rafId = null;
      }
    },

    // ------------------------------------------------------------------
    // startReading() — chiamato dal click del ▶ 
    // inizia la lettura della pagina
    // ------------------------------------------------------------------
    startReading() {
      this.readingStarted = true;
      this.pageStartTime  = performance.now();
      // Registra l'inizio del trial alla prima pagina (non alle successive)
      if (this.currentPage === 0 && this.currentTrialStartTime === 0)
        this.currentTrialStartTime = performance.now();
      this.startRaf();
    },

    // ------------------------------------------------------------------
    // startQuestionnaire() — chiamato dal click "Invia →" 
    // nella schermata dispositivo
    // ------------------------------------------------------------------
    startQuestionnaire() {
      this.questionnaireStartTime = performance.now();
      $magpie.saveAndNextScreen();
    },

    // ------------------------------------------------------------------
    // submitTimeSummary()
    // Salva un record per ogni trial (lettura + domande) e uno per il
    // questionario, tutti con DataType: 'time_summary', poi avanza.
    // ------------------------------------------------------------------
    submitTimeSummary() {
      const totalMs = this.trialTimeSummary.reduce(
        (s, t) => s + t.readingMs + t.questionsMs, 0
      ) + this.questionnaireMs;

      // Un record per ogni trial
      this.trialTimeSummary.forEach(t => {
        $magpie.addTrialData({
          DataType:      'time_summary',
          Label:         t.label,
          IsPractice:    t.isPractice,
          ReadingMs:        t.readingMs,
          QuestionsMs:      t.questionsMs,
          PauseMs:          t.pauseMs || 0,
          TrialTotalMs:     t.readingMs + t.questionsMs + (t.pauseMs || 0),
        });
      });

      // Record per il questionario
      if (this.questionnaireMs > 0) {
        $magpie.addTrialData({
          DataType:      'time_summary',
          Label:         'Questionario',
          IsPractice:    false,
          ReadingMs:     0,
          QuestionsMs:   0,
          TrialTotalMs:  this.questionnaireMs,
        });
      }

      // Record totale
      $magpie.addTrialData({
        DataType:           'time_summary',
        Label:              'Totale',
        IsPractice:         false,
        ReadingMs:          this.trialTimeSummary.reduce((s, t) => s + t.readingMs, 0),
        QuestionsMs:        this.trialTimeSummary.reduce((s, t) => s + t.questionsMs, 0),
        PauseMs:            this.trialTimeSummary.reduce((s, t) => s + (t.pauseMs||0), 0),
        TrialTotalMs:       totalMs,
        ExperimentTotalMs:  Math.round(performance.now() - this.experimentStartTime),
      });

      $magpie.saveAndNextScreen();
    },

    // ------------------------------------------------------------------
    // experimentTotalMs() — tempo totale dall'avvio (per il template)
    // ------------------------------------------------------------------
    experimentTotalMs() {
      return this.experimentStartTime > 0
        ? Math.round(performance.now() - this.experimentStartTime)
        : 0;
    },

    // ------------------------------------------------------------------
    // formatTime(ms)
    // Converte millisecondi in stringa "Xm Ys" leggibile.
    // ------------------------------------------------------------------
    formatTime(ms) {
      if (!ms || ms <= 0) return '—';
      const totalSec = Math.round(ms / 1000);
      const min = Math.floor(totalSec / 60);
      const sec = totalSec % 60;
      return min > 0 ? `${min}m ${sec}s` : `${sec}s`;
    },

    // ------------------------------------------------------------------
    // shuffledCcOptions(trial, pageNr)
    // Restituisce le due opzioni del check (corretta + distrattore)
    // in ordine casuale. L'ordine viene calcolato una sola volta e
    // salvato in ccOptionsCache, così i re-render non riordinano le opzioni.
    // ------------------------------------------------------------------
    shuffledCcOptions(trial, pageNr) {
      const key = `${trial.item_id}_${pageNr}`;
      if (this.ccOptionsCache[key]) return this.ccOptionsCache[key];
      const correct    = trial[`page${pageNr}_cc_correct`]    || '';
      const distractor = trial[`page${pageNr}_cc_distractor`] || '';
      if (!correct && !distractor) return [];
      const opts = Math.random() < 0.5 ? [correct, distractor] : [distractor, correct];
      this.$set(this.ccOptionsCache, key, opts);
      return opts;
    },

    // ------------------------------------------------------------------
    // enoughRead(trial)
    // Restituisce true se il partecipante ha passato il mouse su almeno
    // il 60% delle parole della pagina corrente (token non-newline).
    // ------------------------------------------------------------------
    enoughRead(trial) {
      const page = trial.pages[this.currentPage] || '';
      const words = page.split(' ').filter(t => t !== '\n').length;
      if (words === 0) return true;
      return Object.keys(this.visitedWords).length >= Math.ceil(words * 0.6);
    },

    // ------------------------------------------------------------------
    // wordsReadPct(trial) — percentuale parole lette, per UI feedback
    // ------------------------------------------------------------------
    wordsReadPct(trial) {
      const page = trial.pages[this.currentPage] || '';
      const words = page.split(' ').filter(t => t !== '\n').length;
      if (words === 0) return 100;
      // Progresso verso la soglia (60% parole = 100% indicatore)
      return Math.min(100, Math.round(Object.keys(this.visitedWords).length / (words * 0.6) * 100));
    },

    // ------------------------------------------------------------------
    // ccAnswered(trial, pageNr)
    // Ritorna true se: la pagina non ha check, oppure il partecipante
    // ha selezionato una risposta (qualsiasi — non verifica la correttezza).
    // Usato solo per assicurarsi che non si avanzi senza aver risposto.
    // ------------------------------------------------------------------
    ccAnswered(trial, pageNr) {
      const question = trial[`page${pageNr}_cc_question`];
      if (!question) return true;      // nessun check su questa pagina
      return this.pageCheckAnswer !== null && this.pageCheckAnswer !== '';
    },

    // ------------------------------------------------------------------
    // saveCheckAndNextPage(trial)
    // Salva il risultato del check nei dati di trial e avanza pagina.
    // ------------------------------------------------------------------
    saveCheckAndNextPage(trial) {
      this._savePageCheck(trial);
      if (this.pageStartTime > 0)
        this.currentTrialReadingMs += performance.now() - this.pageStartTime;
      this.nextPage();
    },

    // ------------------------------------------------------------------
    // saveCheckAndStartQuestions(trial)
    // Salva il risultato del check nell'ultima pagina e passa alle domande.
    // ------------------------------------------------------------------
    saveCheckAndStartQuestions(trial) {
      this._savePageCheck(trial);
      if (this.pageStartTime > 0)
        this.currentTrialReadingMs += performance.now() - this.pageStartTime;
      // Resta nello stesso Screen e passa alla fase familiarità
      this.startQuestions();
    },

    // ------------------------------------------------------------------
    // _savePageCheck(trial) — privato
    // Registra su magpie la risposta al comprehension check della pagina.
    // ------------------------------------------------------------------
    _savePageCheck(trial) {
      const pageNr  = this.currentPage + 1;
      const question = trial[`page${pageNr}_cc_question`];
      if (!question) return;
      // Non salviamo la risposta corretta né l'esito: vengono
      // ricavati in post-processing dal TSV degli stimoli.
      // Questo evita che il partecipante possa alterare facilmente
      // i risultati scaricando il file in caso di fallimento invio.
      $magpie.addTrialData({
        DataType:    'page_check',
        Experiment:  trial.experiment_id,
        Condition:   trial.condition_id,
        ItemId:      trial.item_id,
        Page:        pageNr,
        CheckAnswer: this.pageCheckAnswer || '',
      });
    },




    // ------------------------------------------------------------------
    // questionnaireGoNext()
    // Avanza al prossimo step del questionario applicando la logica
    // di skip per le sezioni condizionali. All'ultimo step chiama
    // saveAndNextScreen() che salva tutto in un'unica riga del CSV.
    // ------------------------------------------------------------------
    questionnaireGoNext() {
      if (this.questionnaireStep >= 4) {
        this.ensureOptionalMeasurements();
        this.questionnaireMs = Math.round(
          this.questionnaireStartTime > 0
            ? performance.now() - this.questionnaireStartTime
            : 0
        );
        $magpie.saveAndNextScreen();
        return;
      }
      let next = this.questionnaireStep + 1;
      const m  = this.$magpie.measurements;
      const has = (v) => v && String(v).trim() !== '';

      if (next > 4) {
        this.ensureOptionalMeasurements();
        $magpie.saveAndNextScreen();
        return;
      }
      this.questionnaireStep = next;
      this.$nextTick(() => {
        const wrapper = this.$el.querySelector('.questionnaire-wrapper');
        if (wrapper) wrapper.scrollTop = 0;
      });
    },

    // ------------------------------------------------------------------
    // ensureOptionalMeasurements()
    // Garantisce che tutte le chiavi delle domande del questionario,
    // incluse quelle opzionali (es. lingue native 2/3), siano presenti
    // in $magpie.measurements al momento dell'invio, anche se l'utente
    // non ha risposto/non erano applicabili. Alcuni backend magpie
    // rispondono 422 se una colonna attesa dallo schema risulta assente
    // dalla riga inviata (chiave mancante vs. valore vuoto).
    // ------------------------------------------------------------------
    ensureOptionalMeasurements() {
      const m = this.$magpie.measurements;
      const optionalKeys = [
        'native_language_2',
        'native_language_3',
      ];
      optionalKeys.forEach((k) => {
        if (m[k] === undefined || m[k] === null) {
          m[k] = '';
        }
      });
    },

    questionnaireGoBack() {
      let prev = this.questionnaireStep - 1;
      const m  = this.$magpie.measurements;
      const has = (v) => v && String(v).trim() !== '';

      if (prev < 1) prev = 1;
      this.questionnaireStep = prev;
      this.$nextTick(() => {
        const wrapper = this.$el.querySelector('.questionnaire-wrapper');
        if (wrapper) wrapper.scrollTop = 0;
      });
    },

    // ------------------------------------------------------------------
    // changeBack()
    // Chiamata quando il mouse esce dall'area del testo.
    // Rimuove le classi animate del cursore e resetta la parola corrente.
    // ------------------------------------------------------------------
    changeBack() {
      this.$el.querySelector('.oval-cursor').classList.remove('grow');
      this.$el.querySelector('.oval-cursor').classList.remove('blank');
      this.currentIndex = null;
    },

    // ------------------------------------------------------------------
    // saveData(timestamp)
    // Chiamata dal rAF loop ogni ~50ms. Registra: parola corrente,
    // posizione mouse, bounding box parola, metadati trial, tempi.
    // timestamp = DOMHighResTimeStamp passato da requestAnimationFrame.
    // TrialTime = ms dall'inizio della lettura della pagina (come ET).
    // ------------------------------------------------------------------
    saveData(timestamp) {
      // Guard unico: esci subito se non siamo in fase di lettura attiva.
      // Questo evita qualsiasi querySelector durante il questionario o
      // altre schermate, eliminando micro-freeze sui dropdown.
      if (!this.showFirstDiv || !this.readingStarted || this.currentIndex === null) return;

      // A questo punto siamo certamente nella fase lettura: gli elementi
      // esistono nel DOM. Il querySelector è un safety check.
      const expEl  = this.$el.querySelector('.experiment_id');
      const condEl = this.$el.querySelector('.condition_id');
      const itemEl = this.$el.querySelector('.item_id');
      if (!expEl || !condEl || !itemEl) return;

      // TrialTime: ms trascorsi dall'inizio della pagina (onset ▶)
      // Comparabile con il timestamp relativo dei sistemi di eye-tracking.
      const trialTime = this.pageStartTime > 0
        ? Math.round(timestamp - this.pageStartTime)
        : null;

      const currentElement = this.$el.querySelector(`span[data-index="${this.currentIndex}"]`);
      if (currentElement) {
        // getBoundingClientRect() dentro rAF non causa forced reflow:
        // il layout è già stato calcolato per questo frame.
        const rect = currentElement.getBoundingClientRect();
        $magpie.addTrialData({
          Experiment:          expEl.value,
          Condition:           condEl.value,
          ItemId:              itemEl.value,
          Page:                this.currentPage + 1,
          Index:               this.currentIndex,
          Word:                currentElement.innerHTML.trim(),
          mousePositionX:      this.mousePosition.x,
          mousePositionY:      this.mousePosition.y,
          wordPositionTop:     rect.top,
          wordPositionLeft:    rect.left,
          wordPositionBottom:  rect.bottom,
          wordPositionRight:   rect.right,
          TrialTime:           trialTime,
          SampleTimestamp:     Math.round(timestamp),
        });
      } else {
        $magpie.addTrialData({
          Experiment:      expEl.value,
          Condition:       condEl.value,
          ItemId:          itemEl.value,
          Page:            this.currentPage + 1,
          Index:           this.currentIndex,
          mousePositionX:  this.mousePosition.x,
          mousePositionY:  this.mousePosition.y,
          TrialTime:       trialTime,
          SampleTimestamp: Math.round(timestamp),
        });
      }
    },

    // ------------------------------------------------------------------
    // moveCursor(e)
    // Gestore @mousemove: aggiorna la posizione del cursore ovale,
    // identifica quale <span>/parola è sotto il mouse, aggiorna currentIndex.
    // ------------------------------------------------------------------
    moveCursor(e) {
      this.isCursorMoving = true;
      this.$el.querySelector('.oval-cursor').classList.add('grow');

      const x = e.clientX;
      const y = e.clientY;

      // IMPORTANTE: elementFromPoint() può restituire null se il punto è fuori
      // dal viewport o sopra un elemento con z-index che non supporta .closest().
      // Senza questo controllo, null.closest('span') lancia un TypeError silenzioso
      // che interrompe permanentemente il gestore e blocca il pulsante per sempre.
      const elAtPoint = document.elementFromPoint(x, y);
      const elementAtCursor = elAtPoint ? elAtPoint.closest('span') : null;

      if (elementAtCursor) {
        this.$el.querySelector('.oval-cursor').classList.remove('blank');
        this.currentIndex = elementAtCursor.getAttribute('data-index');
      } else {
        this.$el.querySelector('.oval-cursor').classList.add('blank');
        // Tenta 3px sopra (utile per gli spazi tra righe)
        const elAbove = document.elementFromPoint(x, y - 3);
        const elementAbove = elAbove ? elAbove.closest('span') : null;
        this.currentIndex = elementAbove ? elementAbove.getAttribute('data-index') : -1;
      }

      this.$el.querySelector('.oval-cursor').style.left = `${x + 12}px`;
      this.$el.querySelector('.oval-cursor').style.top  = `${y - 6}px`;
      this.mousePosition.x = x;
      this.mousePosition.y = y;
    },

    // ------------------------------------------------------------------
    // nextPage()
    // Avanza alla pagina successiva del testo corrente.
    // Resetta isCursorMoving per richiedere un nuovo movimento prima
    // di sbloccare il pulsante sulla nuova pagina.
    // ------------------------------------------------------------------
    nextPage() {
      this.stopRaf();
      // Accumula il tempo di lettura della pagina corrente prima di resettare pageStartTime
      if (this.pageStartTime > 0)
        this.currentTrialReadingMs += performance.now() - this.pageStartTime;
      this.ccBoxVisible    = true;
      this.currentPage++;
      this.pageCheckAnswer = null;
      this.visitedWords    = {};
      this.isCursorMoving  = false;
      this.currentIndex    = null;
      this.readingStarted  = false;
      this.pageStartTime   = 0;
      this.$el.querySelector('.oval-cursor').classList.remove('grow');
      this.$el.querySelector('.oval-cursor').classList.remove('blank');
    },

    // ------------------------------------------------------------------
    // startQuestions()
    // Chiamata quando il partecipante ha finito di leggere tutte le pagine.
    // Passa alla fase delle domande di comprensione.
    // ------------------------------------------------------------------
    startQuestions() {
      this.stopRaf();
      // Accumula il tempo dell'ultima pagina prima di resettare pageStartTime
      if (this.pageStartTime > 0)
        this.currentTrialReadingMs += performance.now() - this.pageStartTime;
      this.showFirstDiv        = false;
      this.currentPage         = 0;
      this.pageCheckAnswer     = null;
      this.visitedWords        = {};
      this.pageStartTime       = 0;
      this.currentQuestion     = 0;
      this.currentResponse     = null;
      this.collectedResponses  = [];
    },

    // ------------------------------------------------------------------
    // nextQuestion(trial)
    // Salva la risposta alla domanda corrente e passa alla domanda successiva.
    // ------------------------------------------------------------------
    nextQuestion(trial) {
      // Salva la risposta corrente nell'array temporaneo
      this.collectedResponses.push({
        questionIndex: this.currentQuestion + 1,  // 1-based
        question:      trial.questions[this.currentQuestion].question,
        response:      this.currentResponse,
        correct:       trial.questions[this.currentQuestion].correct,
        isCorrect:     this.currentResponse === trial.questions[this.currentQuestion].correct,
      });

      // Avanza alla domanda successiva e resetta la risposta selezionata
      this.currentQuestion++;
      this.currentResponse = null;
    },

    // ------------------------------------------------------------------
    // submitTrial(trial)
    // Chiamata all'ultima domanda. Salva tutte le risposte su magpie,
    // resetta lo stato per il trial successivo, avanza alla screen seguente.
    // ------------------------------------------------------------------
    submitTrial(trial) {
      // Aggiunge l'ultima risposta
      this.collectedResponses.push({
        questionIndex: this.currentQuestion + 1,
        question:      trial.questions[this.currentQuestion].question,
        response:      this.currentResponse,
        correct:       trial.questions[this.currentQuestion].correct,
        isCorrect:     this.currentResponse === trial.questions[this.currentQuestion].correct,
      });

      // Salva tutte le risposte alle domande come trial data su magpie.
      // Ogni risposta diventa una riga separata nel dataset finale.
      this.collectedResponses.forEach(r => {
        $magpie.addTrialData({
          Experiment:    trial.experiment,
          Condition:     trial.condition,
          ItemId:        trial.item_id,
          DataType:      'comprehension_response',  // distingue i dati di tracking da quelli di risposta
          QuestionIndex: r.questionIndex,
          Question:      r.question,
          Response:      r.response,
          Correct:       r.correct,
          IsCorrect:     r.isCorrect,
        });
      });

      // Calcola i tempi PRIMA di resettare qualsiasi stato
      const questionsMs = this.questionsStartTime > 0
        ? Math.round(performance.now() - this.questionsStartTime)
        : 0;
      const trialTotalElapsedMs = this.currentTrialStartTime > 0
        ? Math.round(performance.now() - this.currentTrialStartTime)
        : 0;
      const activeMs = Math.round(this.currentTrialReadingMs) + questionsMs;
      const pauseMs  = Math.max(0, trialTotalElapsedMs - activeMs);
      const practiceCount = this.trialTimeSummary.filter(t => t.isPractice).length;
      const realCount     = this.trialTimeSummary.filter(t => !t.isPractice).length;
      const isPractice    = trial.condition === 'practice';
      const label         = isPractice
        ? `Pratica ${practiceCount + 1}`
        : `Testo ${realCount + 1}`;
      this.trialTimeSummary.push({
        label,
        isPractice,
        readingMs:   Math.round(this.currentTrialReadingMs),
        questionsMs,
        pauseMs,
      });

      // Reset stato — dopo aver calcolato tutto
      this.showFirstDiv          = true;
      this.familiarityAnswer     = null;
      this.visitedWords          = {};
      this.pageStartTime         = 0;
      this.currentPage           = 0;
      this.pageCheckAnswer       = null;
      this.currentQuestion       = 0;
      this.currentResponse       = null;
      this.collectedResponses    = [];
      this.isCursorMoving        = false;
      this.currentIndex          = null;
      this.readingStarted        = false;
      this.currentTrialReadingMs = 0;
      this.questionsStartTime    = 0;
      this.currentTrialStartTime = 0;

      // Avanza alla schermata successiva
      $magpie.saveAndNextScreen();
    },

    // ------------------------------------------------------------------
    // submitFamiliarity()
    // Salva la risposta di familiarità e avanza alla schermata successiva.
    // ------------------------------------------------------------------
    submitFamiliarity(trial) {
      $magpie.addTrialData({
        Experiment:  trial.experiment,
        Condition:   trial.condition,
        ItemId:      trial.item_id,
        DataType:    'familiarity',
        Familiarity: this.familiarityAnswer,
      });
      this.familiarityAnswer  = null;
      // Resetta lo stato delle domande prima di entrare nello Screen di comprensione
      this.currentQuestion    = 0;
      this.currentResponse    = null;
      this.collectedResponses = [];
      this.questionsStartTime = performance.now();
      $magpie.saveAndNextScreen();
    },

    // ------------------------------------------------------------------
    // getScreenDimensions() - utility non usata attivamente nel template,
    // utile per normalizzare le coordinate in fase di analisi.
    // ------------------------------------------------------------------
    getScreenDimensions() {
      return {
        window_inner_width:  window.innerWidth,
        window_inner_height: window.innerHeight,
      };
    },
  },
};
</script>


<!-- ================================================================
     STILI CSS
     ================================================================ -->
<style>
  .experiment {
    display: flex;
    align-items: center;
    justify-content: center;
  }

  /* Schermata principale: isolation per mix-blend-mode del cursore */
  .main_screen {
    isolation: isolate;
    width: 100%;
    font-size: 18px;
    line-height: 56px;
  }

  /* ---------------------------------------------------------------
     LAYOUT DEL TESTO
     .text-wrapper è nel flusso normale e definisce l'altezza reale
     del contenuto. .readingText occupa spazio in modo normale (non
     absolute) così spinge i pulsanti sotto di sé.
     .blurry-layer si sovrappone in position:absolute ricalcando
     esattamente il rettangolo di .readingText.
     --------------------------------------------------------------- */
  .text-wrapper {
    position: relative;   /* contiene il blurry-layer assoluto */
    width: 100%;
    flex: 1;              /* occupa tutto lo spazio disponibile sopra cc-box */
    min-height: 0;        /* necessario affinché flex:1 possa ridurre l'altezza */
    overflow: hidden;     /* il testo non sfora nel territorio della cc-box */
  }

  /* Layer interattivo: colore bianco = invisibile su sfondo bianco.
     Rivelato dal cursore ovale tramite mix-blend-mode: difference.
     FIX SPAZIATURA: ogni span ha uno spazio finale incorporato nel testo
     ("{{ word }} "), quindi le parole non collassano in un blocco compatto. */
  .readingText {
    /* NON più position:absolute — occupa spazio nel layout normale */
    color: white;
    text-align: left;
    font-weight: 450;
    cursor: pointer;
    padding: 2% 8%;
    /* Preserva gli a capo e gli spazi del testo originale */
    word-spacing: normal;
    white-space: pre-wrap;
  }

  /* Layer sfocato: si sovrappone esattamente a .readingText */
  .blurry-layer {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    pointer-events: none;   /* non blocca gli eventi mouse verso .readingText */
    color: black;
    text-align: left;
    font-weight: 450;
    padding: 2% 8%;
    white-space: pre-wrap;  /* deve corrispondere a .readingText per sovrapporsi correttamente */
  }

  /* ---------------------------------------------------------------
     INDICATORI DI PAGINA E DOMANDA
     Posizionati in alto a destra, fuori dal flusso del testo.
     --------------------------------------------------------------- */
  .page-indicator,
  .question-indicator {
    position: fixed;
    top: 16px;
    right: 24px;
    font-size: 13px;
    color: #888;
    z-index: 10;
    background: rgba(255,255,255,0.85);
    padding: 2px 8px;
    border-radius: 4px;
  }

  /* ---------------------------------------------------------------
     SEZIONE DOMANDE
     Centrata, con padding laterale e spazio per la button-bar.
     --------------------------------------------------------------- */
  .question-area {
    padding: 5% 8% 60px 8%;   /* padding-bottom lascia spazio al pulsante absolute */
  }

  .question-text {
    margin-bottom: 20px;
    font-weight: bold;
    font-size: 1.05em;
  }

  .options-list {
    text-align: left;
    display: inline-block;
  }

  .option-label {
    display: block;
    margin: 10px 0;
    cursor: pointer;
    font-size: 1em;
  }

  .option-label input[type="radio"] {
    margin-right: 8px;
  }

  /* ---------------------------------------------------------------
     TRIAL BOX — contenitore principale di ogni trial.
     Altezza fissa: il pulsante è sempre nell'angolo in basso a destra
     indipendentemente dall'altezza del testo.
     80vh lascia spazio per la barra del browser; regola se necessario.
     --------------------------------------------------------------- */
  .trial-box {
    position: relative;
    width: 100%;
    height: 80vh;
    min-height: 400px;
    display: flex;
    flex-direction: column;
    overflow: hidden;       /* impedisce lo scroll durante il mouse-tracking */
  }

  /* ---------------------------------------------------------------
     BOX BUTTON BAR — pulsante fisso nell'angolo in basso a destra
     del trial-box. Posizione sempre identica, mai sovrapposto al testo.
     right: 8% = stesso margine orizzontale del testo.
     --------------------------------------------------------------- */
  .box-button-bar {
    position: absolute;
    bottom: 16px;
    right: 8%;
    display: flex;
    gap: 10px;
    z-index: 5;
  }

  /* Stile pulsante di navigazione (testo) — usato nella schermata Invia */
  .nav-button {
    position: static;
    padding: 10px 22px;
    font-size: 15px;
    background: #1a6bb5;
    color: white;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    transition: background 0.2s;
  }

  .nav-button:hover:not(:disabled) {
    background: #1558a0;
  }

  .nav-button:disabled {
    background: #aaa;
    cursor: not-allowed;
  }

  /* Pulsante icona-only quadrato — usato per → e ✓ nei trial */
  .icon-button {
    position: static;
    width: 44px;
    height: 44px;
    font-size: 20px;
    line-height: 1;
    background: #1a6bb5;
    color: white;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    transition: background 0.2s;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 0;
  }

  .icon-button:hover:not(:disabled) {
    background: #1558a0;
  }

  .icon-button:disabled {
    background: #aaa;
    cursor: not-allowed;
  }

  /* Wrapper per la fase di lettura. Contiene il pulsante ▶ e il trial-box.
     NON ha overflow:hidden, così il pulsante con top negativo non viene clippato.
     position:relative serve come riferimento per il pulsante assoluto. */
  .reading-stage {
    position: relative;
    width: 100%;
  }

  /* Pulsante di avvio ▶ — allineato alla prima parola del testo.
     Posizionato relativo a .reading-stage (NON a trial-box) così
     overflow:hidden del trial-box non lo clippa mai. */
  .start-button {
    position: absolute;
    top: -5%;
    left: calc(8% - 52px);    /* 52px = larghezza pulsante (44px) + 8px gap dal testo */
    width: 44px;
    height: 44px;
    font-size: 20px;
    line-height: 1;
    background: #1a6bb5;
    color: white;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    transition: background 0.2s;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 0;
    z-index: 20;
  }

  .start-button:hover {
    background: #1558a0;
  }

  /* Reset del posizionamento assoluto globale precedente.
     I pulsanti magpie del framework possono avere stili propri;
     .nav-button sovrascrive con position:static per stare nella button-bar. */
  button {
    position: static;
  }

  /* ---------------------------------------------------------------
     CURSORE OVALE (lente di lettura)
     Parte minuscolo (1×1px), si espande a 102×38px sopra le parole.
     mix-blend-mode: difference + colore bianco crea l'effetto che
     "buca" il layer sfocato nero rivelando il testo sottostante.
     --------------------------------------------------------------- */
  .oval-cursor {
    position: fixed;
    z-index: 2;
    width: 1px;
    height: 1px;
    transform: translate(-50%, -50%);
    background-color: white;
    mix-blend-mode: difference;
    border-radius: 50%;
    pointer-events: none;
    transition: width 0.5s, height 0.5s;
  }

  /* Cursore attivo ma tra righe o su spazio: leggermente più piccolo */
  .oval-cursor.grow.blank {
    width: 80px;
    height: 13px;
  }

  /* Cursore attivo sopra una parola: dimensione piena con glow laterale */
  .oval-cursor.grow {
    width: 102px;
    height: 38px;
    border-radius: 50%;
    box-shadow: 30px 0 8px -4px rgba(255, 255, 255, 0.1),
               -30px 0 8px -4px rgba(255, 255, 255, 0.1);
    background-color: rgba(255, 255, 255, 0.3);
    background-blend-mode: screen;
    pointer-events: none;
    transition: width 0.5s, height 0.5s;
    filter: blur(3px);
  }

  /* Nucleo bianco solido al centro: garantisce rivelazione netta della parola */
  .oval-cursor.grow::before {
    content: "";
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    width: 70%;
    height: 70%;
    background-color: white;
    mix-blend-mode: normal;
    border-radius: 50%;
  }

  /* Impedisce selezione accidentale del testo durante il mouse tracking.
     ECCEZIONE: gli input del questionario devono permettere selezione e digitazione. */
  * {
    user-select: none;
    -webkit-user-select: none;
    -moz-user-select: none;
    -ms-user-select: none;
  }

  /* Override per i campi del questionario: permettono input utente */
  .questionnaire-wrapper input[type="text"],
  .questionnaire-wrapper input[type="number"],
  .questionnaire-wrapper select,
  .questionnaire-wrapper textarea {
    user-select: text;
    -webkit-user-select: text;
    -moz-user-select: text;
    -ms-user-select: text;
  }

  /* ---------------------------------------------------------------
     STILI QUESTIONARIO FINALE (multi-step)
     --------------------------------------------------------------- */
  .questionnaire-screen {
    overflow-y: auto;
  }

  .questionnaire-wrapper {
    width: 44em;
    max-width: 95vw;
    margin: 2em auto 4em;
    font-size: 16px;
    line-height: 1.6;
  }

  /* Barra di avanzamento step */
  .q-progress-bar-wrap {
    height: 6px;
    background: #e0e0e0;
    border-radius: 3px;
    margin-bottom: 6px;
  }

  .q-progress-bar {
    height: 100%;
    background: #1a6bb5;
    border-radius: 3px;
    transition: width 0.4s ease;
  }

  .q-progress-label {
    font-size: 12px;
    color: #999;
    margin-bottom: 1.5em;
  }

  .questionnaire-title {
    font-size: 1.3em;
    font-weight: bold;
    margin-bottom: 0.3em;
  }

  .questionnaire-intro {
    color: #555;
    margin-bottom: 2em;
  }

  /* Sottotitolo di sezione interna */
  .q-subtitle {
    font-size: 1.05em;
    font-weight: 600;
    margin: 1.5em 0 0.5em;
    padding-bottom: 4px;
    border-bottom: 1px solid #ddd;
  }

  /* Testo di aiuto grigio sotto una domanda */
  .q-hint {
    font-size: 13px;
    color: #888;
    margin-top: -8px;
    margin-bottom: 12px;
  }

  /* Blocco singola domanda (spaziatura normale) */
  .q-block {
    margin-bottom: 1.8em;
  }

  /* Blocco compatto per le categorie di lettura (label a sinistra, select a destra) */
  .q-block-sm {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 10px;
    gap: 16px;
  }

  .q-label {
    display: block;
    font-weight: 600;
    margin-bottom: 0.5em;
  }

  /* Label compatta per le categorie di lettura */
  .q-label-sm {
    flex: 1;
    font-size: 14px;
    font-weight: normal;
    min-width: 0;
  }

  /* Input testo e numero */
  .q-input-text {
    width: 100%;
    padding: 8px 12px;
    font-size: 15px;
    border: 1px solid #ccc;
    border-radius: 6px;
    box-sizing: border-box;
    transition: border-color 0.2s;
  }

  .q-input-text:focus {
    outline: none;
    border-color: #1a6bb5;
  }

  /* Input numerico stretto (es. età) */
  .q-input-narrow {
    width: 120px;
  }

  /* Menu a tendina */
  .q-select {
    padding: 8px 12px;
    font-size: 15px;
    border: 1px solid #ccc;
    border-radius: 6px;
    background: white;
    cursor: pointer;
    transition: border-color 0.2s;
    min-width: 220px;
  }

  /* Select compatto nelle righe di lettura */
  .q-block-sm .q-select {
    min-width: 180px;
    width: 180px;
    flex-shrink: 0;
  }

  .q-select:focus {
    outline: none;
    border-color: #1a6bb5;
  }

  /* Textarea */
  .q-textarea {
    width: 100%;
    padding: 8px 12px;
