  }

  /* Pulsante Indietro: grigio */
  .q-btn-back {
    background: #888 !important;
  }

  .q-btn-back:hover {
    background: #666 !important;
  }
  /* ---------------------------------------------------------------
     OVERLAY BLOCCO SMARTPHONE
     Copre tutto lo schermo impedendo l'accesso all'esperimento.
     --------------------------------------------------------------- */
  .mobile-block-overlay {
    position: fixed;
    inset: 0;
    background: rgba(255,255,255,0.97);
    z-index: 9999;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 24px;
  }

  .mobile-block-box {
